   633→// Interface for chart data structure
   634→export interface HoraryChartData {
   635→  planets: {
   636→    [key: string]: {
   637→      position: number;
   638→      isRetrograde: boolean;
   639→    };
   640→  };
   641→  cusps: number[]; // house cusps in degrees
   642→  aspects?: string[];
   643→}
   644→
   645→export interface HoraryReading {
   646→  question: string;
