   648→  location?: {
   649→    latitude: number;
   650→    longitude: number;
   651→  };
   652→  chartData: HoraryChartData;
   653→}
   654→
   655→// Helper function to convert degrees to sign and degree
   656→function degreesToSignAndDegree(degrees: number): {
   657→  sign: string;
   658→  degree: number;
   659→} {
   660→  const signs = [
   661→    "Aries",
   662→    "Taurus",
   663→    "Gemini",
   664→    "Cancer",
   665→    "Leo",
   666→    "Virgo",
   667→    "Libra",
   668→    "Scorpio",
   669→    "Sagittarius",
   670→    "Capricorn",
   671→    "Aquarius",
   672→    "Pisces",
   673→  ];
   674→
   675→  const normalizedDegrees = ((degrees % 360) + 360) % 360;
   676→  const signIndex = Math.floor(normalizedDegrees / 30);
   677→  const degree = normalizedDegrees % 30;
   678→
   679→  return {
   680→    sign: signs[signIndex],
   681→    degree: Math.round(degree * 100) / 100,
   682→  };
   683→}
   684→
   685→// Helper function to determine house for a planet
   686→function getPlanetHouse(planetDegrees: number, cusps: number[]): number {
   687→  const normalizedPlanet = ((planetDegrees % 360) + 360) % 360;
   688→
   689→  for (let i = 0; i < cusps.length; i++) {
   690→    const currentCusp = ((cusps[i] % 360) + 360) % 360;
   691→    const nextCusp = ((cusps[(i + 1) % cusps.length] % 360) + 360) % 360;
   692→
   693→    if (nextCusp > currentCusp) {
   694→      if (normalizedPlanet >= currentCusp && normalizedPlanet < nextCusp) {
   695→        return i + 1;
   696→      }
   697→    } else {
   698→      if (normalizedPlanet >= currentCusp || normalizedPlanet < nextCusp) {
   699→        return i + 1;
   700→      }
   701→    }
   702→  }
   703→
   704→  return 1; // fallback
   705→}
   706→
   707→// Format chart data for the LLM
   708→function formatChartForLLM(reading: HoraryReading): string {
   709→  const { chartData } = reading;
   710→
   711→  let formattedData = `## Chart Data for Question: "${reading.question}"\n`;
   712→  formattedData += `**Time**: ${new Date(
   713→    reading.timestamp
   714→  ).toLocaleString()}\n`;
   715→
   716→  if (reading.location) {
   717→    formattedData += `**Location**: ${reading.location.latitude.toFixed(
   718→      2
   719→    )}°N, ${reading.location.longitude.toFixed(2)}°W\n\n`;
   720→  }
   721→
   722→  // Format planetary positions
   723→  formattedData += `### Planetary Positions:\n`;
   724→  Object.entries(chartData.planets).forEach(([planet, planetData]) => {
   725→    const { sign, degree } = degreesToSignAndDegree(planetData.position);
   726→    const house = getPlanetHouse(planetData.position, chartData.cusps);
   727→    const rxSymbol = planetData.isRetrograde ? " ℞" : "";
   728→    formattedData += `- **${
   729→      planet.charAt(0).toUpperCase() + planet.slice(1)
   730→    }${rxSymbol}**: ${degree.toFixed(2)}° ${sign} (House ${house})\n`;
   731→  });
   732→
   733→  // Format house cusps
   734→  formattedData += `\n### House Cusps:\n`;
   735→  chartData.cusps.forEach((cusp, index) => {
   736→    const { sign, degree } = degreesToSignAndDegree(cusp);
   737→    formattedData += `- **House ${index + 1}**: ${degree.toFixed(
   738→      2
   739→    )}° ${sign}\n`;
   740→  });
   741→
   742→  // Add aspects if available
   743→  if (chartData.aspects && chartData.aspects.length > 0) {
   744→    formattedData += `\n### Major Aspects:\n`;
   745→    chartData.aspects.forEach((aspect) => {
   746→      formattedData += `- ${aspect}\n`;
   747→    });
   748→  }
   749→
   750→  return formattedData;
   751→}
   752→
   753→// Helper function to format LLM errors for user display
   754→function formatLLMError(error: any): string {
   755→  const errorMessage = error?.message || String(error);
   756→
   757→  // Connection refused - Ollama not running
   758→  if (errorMessage.includes('ECONNREFUSED') || errorMessage.includes('Failed to fetch')) {
   759→    return 'Ollama server not running. Please start Ollama and try again.';
   760→  }
   761→
   762→  // 404 - Model not found
   763→  if (errorMessage.includes('404') || errorMessage.includes('not found')) {
   764→    return 'Model not found. Please check your model name in settings or pull the model first.';
   765→  }
   766→
   767→  // Timeout
   768→  if (errorMessage.includes('timeout') || errorMessage.includes('aborted')) {
   769→    return 'Connection timeout. Please check your Ollama server or increase timeout in settings.';
   770→  }
   771→
   772→  // Generic error
   773→  return `Error: ${errorMessage}`;
   774→}
