  id: LLMProvider;
  name: string;
  description: string;
  requiresApiKey: boolean;
  supportsLocal: boolean;
  defaultModel: string;
  suggestedModels: string[];
  apiKeyPlaceholder?: string;
  apiKeyPattern?: RegExp;
  getApiKeyUrl?: string;
}

export type ConnectionStatus = 'idle' | 'testing' | 'success' | 'error';

